function d(){document.querySelectorAll("a[data-plan]").forEach(e=>{e.addEventListener("click",t=>{t.preventDefault();const o=e.getAttribute("data-plan");if(o==="poutnik"){window.Auth?.isLoggedIn()?window.location.href="profil.html":window.Auth?.toggleModal?.();return}l(o,e)})})}async function l(a,e){if(!window.Auth||!window.Auth.isLoggedIn()){window.Auth?.showToast?.("P\u0159ihl\xE1\u0161en\xED vy\u017Eadov\xE1no","Pro n\xE1kup p\u0159edplatn\xE9ho se pros\xEDm nejd\u0159\xEDve p\u0159ihlaste.","info"),window.Auth?.toggleModal?.();return}const t=e.innerHTML;try{e.disabled=!0,e.style.opacity="0.7",e.innerHTML='<span class="loading-spinner" style="width: 16px; height: 16px; border-width: 2px; vertical-align: middle; margin-right: 8px;"></span> P\u0159esm\u011Brov\xE1n\xED...';const o=window.API_CONFIG?.BASE_URL||"/api",s=window.getCSRFToken?await window.getCSRFToken():null,n=await fetch(`${o}/payment/create-checkout-session`,{method:"POST",credentials:"include",headers:{"Content-Type":"application/json",...s&&{"X-CSRF-Token":s}},body:JSON.stringify({planId:a})});if(!n.ok){let r="Nepoda\u0159ilo se vytvo\u0159it platebn\xED relaci";try{r=(await n.json()).error||r}catch{}throw new Error(r)}const i=await n.json();if(i.url)window.location.href=i.url;else throw new Error(i.error||"Nepoda\u0159ilo se vytvo\u0159it platebn\xED relaci")}catch(o){console.error("Payment Error:",o),window.Auth?.showToast?.("Chyba platby",o.message,"error"),e.disabled=!1,e.style.opacity="1",e.innerHTML=t}}export{d as initPaymentButtons};
